The following code - compile with cc -g

#include <stdio.h>
#include <string.h>
#include <strings.h>
#include <stdlib.h>

int main (int argc, char *argv[])
{
        int i, randx, k, p;
        int initial;

        initial = atoi (argv[1]);
        randx = initial;
        k = atoi (argv[2]);
        p = atoi (argv[3]);

        i = 1;
        randx = (k * randx) % p;
        while (randx != initial)
        {
                if (i < 5) printf ("count = %d randx = %d\n", i, randx);
                randx = (k * randx) % p;
                i++;
        }
        printf ("count = %d\n", i);
}

